+    private static func classifyRateWindow(_ window: RateWindow?, slot: SnapshotSlot) -> (RateLane, RateWindow)? {
+        guard let window else { return nil }
+
+        let lane: RateLane = switch window.windowMinutes {
+        case 300:
+            .session
+        case 10080:
+            .weekly
+        default:
+            switch slot {
+            case .primary:
+                .session
+            case .secondary:
+                .weekly
+            }
+        }
