+        let hasExhaustedLane = rateWindowsByLane.values.contains { $0.remainingPercent <= 0 }
+        let hasNoRateWindows = rateWindowsByLane.isEmpty
+        return (hasExhaustedLane || hasNoRateWindows) ? .creditsBalance : .none
+    }
